-- {"operators": "INNER_JOIN,AGGREGATE,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,ITEM,OORDER,ORDER_LINE", "ducklake": true}
WITH top_items AS (SELECT OL_I_ID, SUM(OL_AMOUNT) AS rev FROM dl.ORDER_LINE GROUP BY OL_I_ID) SELECT w.W_ID, d.D_ID, i.I_ID, i.I_NAME, ti.rev FROM dl.WAREHOUSE w JOIN dl.DISTRICT d ON w.W_ID = d.D_W_ID JOIN dl.CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN dl.ORDER_LINE ol ON o.O_W_ID = ol.OL_W_ID AND o.O_D_ID = ol.OL_D_ID AND o.O_ID = ol.OL_O_ID JOIN dl.ITEM i ON ol.OL_I_ID = i.I_ID JOIN top_items ti ON i.I_ID = ti.OL_I_ID GROUP BY w.W_ID, d.D_ID, i.I_ID, i.I_NAME, ti.rev;
